#nullable enable // autogenerated

using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Projectiles;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Blueprints;
using MVZ2Logic.Definitions;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Buffs;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Definitions;
using PVZEngine.SeedPacks;
using UnityEngine;

namespace MVZ2.GameContent.Seeds
{
    [AutoSeedOptionDefinition(VanillaBlueprintNames.heavyWeaponFlashbang)]
    public class HeavyWeaponFlashbang : SeedOptionDefinition
    {
        public HeavyWeaponFlashbang(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Use(SeedPack seedPack)
        {
            base.Use(seedPack);
            Use(seedPack.Level);
        }
        public override void Use(LevelEngine level, SeedDefinition seedDef)
        {
            base.Use(level, seedDef);
            Use(level, seedDef);
        }
        private void Use(LevelEngine level)
        {
            var pos = level.GetLawnCenter();
            level.Spawn(VanillaEffectID.stunningFlash, pos, null);
            bool stunned = false;
            foreach (var target in level.FindEntities(e => e.IsVulnerableEntity() && e.IsHostileEntity() && e.CanDeactive()))
            {
                target.Stun(150);
                stunned = true;
            }
            if (stunned)
            {
                level.PlaySound(VanillaSoundID.stunned);
            }
        }
    }
}
